&lt;h1 id=&#34;驗證-redis-叢集&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#驗證-redis-叢集&#34;&gt;#&lt;/a&gt; 驗證 Redis 叢集&lt;/h1&gt;
&lt;pre class=&#34;shiki shiki-themes vitesse-light vitesse-dark&#34; style=&#34;background-color:#ffffff;--shiki-dark-bg:#121212;color:#393a34;--shiki-dark:#dbd7caee&#34; tabindex=&#34;0&#34;&gt;&lt;code class=&#34;language-shell&#34;&gt;&lt;span class=&#34;line&#34;&gt;&lt;span style=&#34;color:#59873A;--shiki-dark:#80A665&#34;&gt;kubectl&lt;/span&gt;&lt;span style=&#34;color:#B56959;--shiki-dark:#C98A7D&#34;&gt; exec&lt;/span&gt;&lt;span style=&#34;color:#A65E2B;--shiki-dark:#C99076&#34;&gt; -it&lt;/span&gt;&lt;span style=&#34;color:#B56959;--shiki-dark:#C98A7D&#34;&gt; redis-cluster-0&lt;/span&gt;&lt;span style=&#34;color:#A65E2B;--shiki-dark:#C99076&#34;&gt; --&lt;/span&gt;&lt;span style=&#34;color:#B56959;--shiki-dark:#C98A7D&#34;&gt; redis-cli&lt;/span&gt;&lt;span style=&#34;color:#B56959;--shiki-dark:#C98A7D&#34;&gt; cluster&lt;/span&gt;&lt;span style=&#34;color:#B56959;--shiki-dark:#C98A7D&#34;&gt; info&lt;/span&gt;&lt;/span&gt;&lt;/code&gt;&lt;/pre&gt;
&lt;details class=&#34;info&#34;&gt;&lt;summary&gt;執行結果&lt;/summary&gt;&lt;div&gt;
&lt;p&gt;$ kubectl exec -it redis-cluster-0 -- redis-cli cluster info&lt;br /&gt;
cluster_state:ok&lt;br /&gt;
cluster_slots_assigned:16384&lt;br /&gt;
cluster_slots_ok:16384&lt;br /&gt;
cluster_slots_pfail:0&lt;br /&gt;
cluster_slots_fail:0&lt;br /&gt;
cluster_known_nodes:6&lt;br /&gt;
